import React, { useState, useEffect } from 'react';
import axios from 'axios';

function Admin() {
  const [requests, setRequests] = useState([]);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [password, setPassword] = useState('');
  const adminPassword = "admin123";

  const fetchData = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/requests');
      setRequests(res.data);
    } catch (err) { 
      console.error("Error fetching data:", err); 
    }
  };

  useEffect(() => { 
    if (isLoggedIn) fetchData(); 
  }, [isLoggedIn]);

  const handleLogin = (e) => {
    e.preventDefault();
    if (password === adminPassword) setIsLoggedIn(true);
    else alert("Wrong Password!");
  };

  const handleUpdate = async (id) => {
    // ID वरून व्हॅल्यूज मिळवणे
    const updatedStatus = document.getElementById(`status-${id}`).value;
    const updatedProgress = document.getElementById(`progress-${id}`).value;
    const updatedPayment = document.getElementById(`pay-${id}`).value;

    try {
      await axios.put(`http://localhost:5000/api/update-status/${id}`, {
        status: updatedStatus,
        progress: updatedProgress,
        paymentStatus: updatedPayment
      });
      alert("✅ Project Updated!");
      fetchData(); // डेटा रिफ्रेश करा
    } catch (err) {
      alert("❌ Update failed!");
    }
  };

  const handleDelete = async (id) => {
    if (window.confirm("Delete this request?")) {
      try {
        await axios.delete(`http://localhost:5000/api/delete-request/${id}`);
        fetchData();
      } catch (err) {
        alert("Delete failed!");
      }
    }
  };

  if (!isLoggedIn) {
    return (
      <div className="container d-flex justify-content-center align-items-center" style={{minHeight: '80vh'}}>
        <div className="card shadow-lg p-4 border-0 text-center" style={{width: '350px'}}>
          <h3 className="fw-bold mb-4">Admin Login</h3>
          <form onSubmit={handleLogin}>
            <input type="password" placeholder="Password" className="form-control mb-3 py-2" value={password} onChange={(e) => setPassword(e.target.value)} required />
            <button className="btn btn-primary w-100 fw-bold py-2 shadow">Login</button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="container-fluid py-5 px-lg-5">
      <div className="d-flex justify-content-between align-items-center mb-4">
        <h2 className="fw-bold text-primary">Freelancer Dashboard</h2>
        <button className="btn btn-sm btn-outline-danger" onClick={() => setIsLoggedIn(false)}>Logout</button>
      </div>

      <div className="table-responsive shadow-sm rounded-4 bg-white p-2">
        <table className="table table-hover align-middle">
          <thead className="table-light text-secondary">
            <tr>
              <th className="ps-3">Client & Service</th>
              <th>Payment Status</th>
              <th>Progress (%)</th>
              <th>Work Status</th>
              <th className="text-center">Action</th>
            </tr>
          </thead>
          <tbody>
            {requests.length > 0 ? requests.map((req) => (
              <tr key={req._id}>
                <td className="ps-3">
                  <div className="fw-bold">{req.fullName}</div>
                  <small className="text-muted">{req.serviceType}</small>
                </td>
                <td>
                  <select id={`pay-${req._id}`} className={`form-select form-select-sm fw-bold ${req.paymentStatus === 'Paid' ? 'text-success' : 'text-danger'}`} defaultValue={req.paymentStatus}>
                    <option value="Unpaid">Unpaid</option>
                    <option value="Paid">Paid</option>
                  </select>
                </td>
                <td>
                  <div className="d-flex align-items-center gap-2">
                    <input 
                      type="number" id={`progress-${req._id}`} 
                      className="form-control form-control-sm" 
                      defaultValue={req.progress} min="0" max="100" 
                      style={{ width: '60px' }} 
                    />
                    <div className="progress flex-grow-1 d-none d-md-flex" style={{ height: '6px' }}>
                      <div className="progress-bar bg-primary" style={{ width: `${req.progress}%` }}></div>
                    </div>
                  </div>
                </td>
                <td>
                  <select id={`status-${req._id}`} className="form-select form-select-sm" defaultValue={req.status}>
                    <option value="Pending">Pending</option>
                    <option value="In Progress">In Progress</option>
                    <option value="Completed">Completed</option>
                  </select>
                </td>
                <td className="text-center">
                  <div className="btn-group shadow-sm">
                    <button className="btn btn-success btn-sm px-3" onClick={() => handleUpdate(req._id)}>Save</button>
                    <button className="btn btn-light btn-sm text-danger border" onClick={() => handleDelete(req._id)}>
                      <i className="bi bi-trash"></i> Delete
                    </button>
                  </div>
                </td>
              </tr>
            )) : (
                <tr><td colSpan="5" className="text-center py-5 text-muted">No requests found yet!</td></tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}

export default Admin;
